import React from 'react';
import { isFunction } from '../util';
import { useIsomorphicLayoutEffect as useLayoutEffect } from './useIsomorphicLayoutEffect';

/**
 * 可以比 useLayoutEffect 更早执行，但是父子节点的执行顺序与 useLayoutEffect 是相反的。这个方法要慎用，因为 strict mode render 会跑两次
 */
export function useRenderEffect(effect: React.EffectCallback) {
  const isFirstRenderRef = React.useRef<boolean>(true);
  const destructorRef = React.useRef<ReturnType<React.EffectCallback>>();
  const prevEffect = React.useRef<React.EffectCallback>();
  if (isFirstRenderRef.current || prevEffect.current !== effect) {
    if (isFunction(destructorRef.current)) {
      destructorRef.current();
    }
    destructorRef.current = effect();
    prevEffect.current = effect;
  }
  if (isFirstRenderRef.current) {
    isFirstRenderRef.current = false;
  }
  useLayoutEffect(
    () => () => {
      if (isFunction(destructorRef.current)) {
        destructorRef.current();
        destructorRef.current = undefined;
      }
      prevEffect.current = undefined;
    },
    [],
  );
}
